// Import reads beads from an external source and merges them into the store.
// Returns the number of beads imported.
func (s *Store) Import(source, filePath string) (int, error) {
	if source == "" || source == "auto" {
		return s.importAuto(filePath)
	}

	switch source {
	case "bd":
		return s.importFromTool("bd")
	case "br":
		return s.importFromTool("br")
	case "jsonl":
		return s.importFromJSONL(filePath)
	default:
		return 0, fmt.Errorf("bead: unknown import source: %s", source)
	}
}

// ExportTo writes all beads as JSONL to the given writer.
//
// For interchange compatibility with bd/br, externalized event histories are
// inlined back into the row's "events" array on the way out (the attachment
// ref itself is also dropped so importers don't see a dangling pointer).
// The on-disk row is unchanged — this is a transient mutation on the copied
// Bead value before marshaling.
//
// When called on the active collection, archived beads from the
// beads-archive partner are also streamed inline so a single export carries
// the full corpus. Each archived bead's externalized events are loaded from
// the active store's attachment dir (where Migrate writes them) before
// emission.
func (s *Store) ExportTo(w io.Writer) error {
	beads, err := s.ReadAll(context.Background())
	if err != nil {
		return err
	}
	seen := make(map[string]bool, len(beads))
	for _, b := range beads {
		seen[b.ID] = true
		if hasEventsAttachment(&b) {
			if err := s.inlineEventsInPlace(&b); err != nil {
				return fmt.Errorf("bead: export inline events: %w", err)
			}
		}
		data, err := marshalBead(b)
		if err != nil {
			return fmt.Errorf("bead: export marshal: %w", err)
		}
		if _, err := fmt.Fprintf(w, "%s\n", data); err != nil {
			return fmt.Errorf("bead: export write: %w", err)
		}
	}

	if s.Collection != DefaultCollection {
		return nil
	}
	archive := s.archivePartner()
	archived, aerr := archive.ReadAll(context.Background())
	if aerr != nil {
		// Treat a missing/unreadable archive partner as empty — the
		// active collection is still a valid export.
		return nil
	}
	for _, b := range archived {
		if seen[b.ID] {
			continue
		}
		if hasEventsAttachment(&b) {
			// Attachments live under the active store's .ddx/attachments
			// dir even after the bead moves to the archive (Migrate
			// writes them there before archival). Use s, not archive,
			// to resolve the sidecar path.
			if err := s.inlineEventsInPlace(&b); err != nil {
				return fmt.Errorf("bead: export inline events: %w", err)
			}
		}
		data, err := marshalBead(b)
		if err != nil {
			return fmt.Errorf("bead: export marshal: %w", err)
		}
		if _, err := fmt.Fprintf(w, "%s\n", data); err != nil {
			return fmt.Errorf("bead: export write: %w", err)
		}
	}
	return nil
}

// ExportToFile writes all beads as JSONL to the given file path.
func (s *Store) ExportToFile(filePath string) error {
	dir := filepath.Dir(filePath)
	if err := os.MkdirAll(dir, 0o755); err != nil {
		return fmt.Errorf("bead: export mkdir: %w", err)
	}
	f, err := os.Create(filePath)
	if err != nil {
		return fmt.Errorf("bead: export create: %w", err)
	}
	defer f.Close()
	return s.ExportTo(f)
}

// migrateFromHelix checks for .helix/issues.jsonl and imports beads into the
// DDx store if it exists and the DDx store is empty. Returns (count, migrated, error).
func (s *Store) migrateFromHelix() (int, bool, error) {
	helixFile := ".helix/issues.jsonl"
	if _, err := os.Stat(helixFile); err != nil {
		return 0, false, nil // no HELIX tracker, nothing to do
	}

	// Check if DDx store already has beads
	existing, err := s.ReadAll(context.Background())
	if err == nil && len(existing) > 0 {
		return 0, false, nil // DDx store already populated
	}

	n, err := s.importFromJSONL(helixFile)
	if err != nil {
		return 0, false, fmt.Errorf("bead: migrate from .helix/issues.jsonl: %w", err)
	}
	return n, n > 0, nil
}

func (s *Store) importAuto(filePath string) (int, error) {
	// Try bd
	if _, err := exec.LookPath("bd"); err == nil {
		n, err := s.importFromTool("bd")
		if err == nil && n > 0 {
			return n, nil
		}
	}

	// Try br
	if _, err := exec.LookPath("br"); err == nil {
		n, err := s.importFromTool("br")
		if err == nil && n > 0 {
			return n, nil
		}
	}

	// Try known bead file locations in priority order
	beadsFile := filePath
	if beadsFile == "" {
		for _, candidate := range []string{
			".beads/issues.jsonl", // bd default
			".helix/issues.jsonl", // HELIX legacy tracker
		} {
			if _, err := os.Stat(candidate); err == nil {
				beadsFile = candidate
				break
			}
		}
		if beadsFile == "" {
			beadsFile = ".beads/issues.jsonl" // fallback for error message
		}
	}
	return s.importFromJSONL(beadsFile)
}

func (s *Store) importFromTool(tool string) (int, error) {
	cmd := exec.Command(tool, "list", "--json")
	output, err := cmd.Output()
	if err != nil {
		return 0, fmt.Errorf("bead: %s list --json: %w", tool, err)
	}

	return s.mergeJSONL(string(output))
}

func (s *Store) importFromJSONL(path string) (int, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return 0, fmt.Errorf("bead: read %s: %w", path, err)
	}
	return s.mergeJSONL(string(data))
}

func (s *Store) mergeJSONL(data string) (int, error) {
	var incoming []Bead
	var parseErrors int

	// Try as JSON array first, then as JSONL
	trimmed := strings.TrimSpace(data)
	if strings.HasPrefix(trimmed, "[") {
		var raw []json.RawMessage
		if err := json.Unmarshal([]byte(trimmed), &raw); err != nil {
			return 0, fmt.Errorf("bead: import parse: %w", err)
		}
		for _, r := range raw {
			b, err := unmarshalBead(r)
			if err != nil {
				parseErrors++
				continue
			}
			incoming = append(incoming, b)
		}
	} else {
		for _, line := range strings.Split(trimmed, "\n") {
			line = strings.TrimSpace(line)
			if line == "" {
				continue
			}
			b, err := unmarshalBead([]byte(line))
			if err != nil {
				parseErrors++
				continue
			}

	}
	delete(b.Extra, ClaimHeartbeatExtraKey)
}

func firstNonEmpty(values ...string) string {
	for _, v := range values {
		if trimmed := strings.TrimSpace(v); trimmed != "" {
			return trimmed
		}
	}
	return ""
}

// Migrate splits the existing active beads collection into the modern
// layout: closed beads' inline events are externalized to the attachment
// store (per ADR-004), and eligible closed beads are moved to the
// beads-archive partner (per TD-027). It is idempotent — a second call
// with no further changes is a no-op.
//
// Migrate uses a permissive archival policy (MinAge=0, MinActiveCount=0)
// so it drains the historical backlog. Routine archival (after Close)
// uses the policy assembled by `ddx bead archive` from its flag set.
func (s *Store) Migrate() (MigrateStats, error) {
	return s.ArchiveWithEvents(migratePolicy())
}

// migrateDryRun reports what Migrate would do without mutating disk. It uses
// the same eligibility logic as Migrate (Statuses=[closed], no MinAge floor,
// preserve_dependencies retention).
func (s *Store) migrateDryRun() (MigrateStats, error) {
	var stats MigrateStats
	if s.Collection != DefaultCollection {
		return stats, fmt.Errorf("bead: migrate dry-run only runs from the active %q collection (got %q)", DefaultCollection, s.Collection)
	}
	policy := migratePolicy()

	var beads []Bead
	err := s.WithLock(func() error {
		all, _, rerr := s.readAllLatestRaw()
		if rerr != nil {
			return rerr
		}
		beads = all
		return nil
	})
	if err != nil {
		return stats, err
	}

	referenced := make(map[string]bool)
	for _, b := range beads {
		if b.Status == StatusClosed {
			continue
		}
		for _, dep := range b.DepIDs() {
			referenced[dep] = true
		}
	}

	for _, b := range beads {
		if !containsString(policy.Statuses, b.Status) {
			continue
		}
		if hasInlineEvents(&b) {
			stats.EventsExternalized++
			stats.EventRecordsExternalized += inlineEventCount(&b)
			stats.AttachmentsTouched++
		}
		if referenced[b.ID] {
			continue
		}
		ts := b.UpdatedAt
		if raw, ok := b.Extra["closed_at"].(string); ok {
			if parsed, perr := time.Parse(time.RFC3339, raw); perr == nil {
				ts = parsed
			}
		}
		if policy.MinAge > 0 && time.Now().UTC().Sub(ts) < policy.MinAge {
			continue
		}
		stats.Archived++
	}
	return stats, nil
}

func migratePolicy() ArchivePolicy {
	return ArchivePolicy{
		Statuses:       []string{StatusClosed},
		MinAge:         0,
		MinActiveCount: 0,
		BatchSize:      0,
	}
}

// ArchiveWithEvents externalizes inline events for every bead whose status
// matches policy.Statuses, then archives eligible beads under the same
// policy. This is the operator-facing path used by `ddx bead archive` and
// the internal path used by `ddx bead migrate`.
func (s *Store) ArchiveWithEvents(policy ArchivePolicy) (MigrateStats, error) {
	var stats MigrateStats
	if s.Collection != DefaultCollection {
		return stats, fmt.Errorf("bead: archive only runs from the active %q collection (got %q)", DefaultCollection, s.Collection)
	}

	// Step 1: externalize inline events on every eligible-status bead under
	// the active store's lock. This shrinks the row size before we try to
	// archive, so the archive partner inherits already-thin rows.
	err := s.WithLock(func() error {
		beads, _, rerr := s.readAllLatestRaw()
		if rerr != nil {
			return rerr
		}
		dirty := false
		for i := range beads {
			if !containsString(policy.Statuses, beads[i].Status) {
				continue
			}
			if !hasInlineEvents(&beads[i]) {
				continue
			}
			stats.EventsExternalized++
			stats.EventRecordsExternalized += inlineEventCount(&beads[i])
			stats.AttachmentsTouched++
			if eerr := s.externalizeEventsInPlace(&beads[i]); eerr != nil {
				return eerr
			}
			dirty = true
		}
		if !dirty {
			return nil
		}
		return s.WriteAll(beads)
	})
	if err != nil {
		return stats, fmt.Errorf("bead: archive externalize: %w", err)
	}

	moved, err := s.Archive(policy)
	if err != nil {
		return stats, fmt.Errorf("bead: archive: %w", err)
	}
	stats.Archived = len(moved)
	return stats, nil
}

