func (f *CommandFactory) newBeadCreateCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "create <title>",
		Short: "Create a new bead",
		Args:  cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			if err := f.checkLifecycleMigrationGate(cmd); err != nil {
				return err
			}
			s := f.beadStore()
			b := &bead.Bead{Title: args[0]}

			if v, _ := cmd.Flags().GetString("type"); v != "" {
				b.IssueType = v
			}
			if v, _ := cmd.Flags().GetInt("priority"); cmd.Flags().Changed("priority") {
				b.Priority = v
			}
			if v, _ := cmd.Flags().GetString("labels"); v != "" {
				b.Labels = strings.Split(v, ",")
			}
			if v, _ := cmd.Flags().GetString("acceptance"); v != "" {
				b.Acceptance = v
			}
			if v, _ := cmd.Flags().GetString("description"); v != "" {
				b.Description = v
			}
			if v, _ := cmd.Flags().GetString("parent"); v != "" {
				b.Parent = v
			}
			if dependsOn, _ := cmd.Flags().GetStringSlice("depends-on"); len(dependsOn) > 0 {
				normalized := make([]string, 0, len(dependsOn))
				for _, depID := range dependsOn {
					if depID = strings.TrimSpace(depID); depID != "" {
						normalized = append(normalized, depID)
					}
				}
				if len(normalized) > 0 {
					if b.ID == "" {
						id, err := s.GenID(context.Background())
						if err != nil {
							return err
						}
						b.ID = id
					}
					for _, depID := range normalized {
						b.AddDep(depID, "blocks")
					}
				}
			}
			if setFlags, _ := cmd.Flags().GetStringArray("set"); len(setFlags) > 0 {
				if b.Extra == nil {
					b.Extra = make(map[string]any)
				}
				for _, kv := range setFlags {
					k, v, ok := strings.Cut(kv, "=")
					if !ok {
						return fmt.Errorf("--set requires key=value format, got: %s", kv)
					}
					if err := bead.SetExtraValue(b.Extra, k, v); err != nil {
						return err
					}
				}
			}
			if err := f.validateExecuteBeadCreate(cmd, s, b); err != nil {
				return err
			}

			if err := f.withBeadTrackerWriteLock(func() error {
				if err := s.Create(context.Background(), b); err != nil {
					return err
				}
				if markerPresent, _ := s.HasLifecycleSchemaMarker(); !markerPresent && !beadHasLegacyLifecycleInputs(*b) {
					if err := s.WriteLifecycleSchemaMarker(time.Now().UTC()); err != nil {
						return err
					}
				}
				if _, err := f.beadAutoCommitPaths("create "+b.ID, []string{s.File, s.LifecycleSchemaMarkerPath()}); err != nil {
					return err
				}
				return nil
			}); err != nil {
				return err
			}
			fmt.Fprintf(cmd.OutOrStdout(), "%s\n", b.ID)
			return nil
		},
	}

	cmd.Flags().String("type", "", "Bead type (task, bug, epic, chore)")
	cmd.Flags().Int("priority", 2, "Priority (0=highest, 4=lowest)")
	cmd.Flags().String("labels", "", "Comma-separated labels")
	cmd.Flags().String("acceptance", "", "Acceptance criteria")
	cmd.Flags().String("description", "", "Description")
	cmd.Flags().String("parent", "", "Parent bead ID")
	cmd.Flags().StringSlice("depends-on", nil, "Dependency bead ID (comma-separated or repeated)")
	cmd.Flags().StringArray("set", nil, "Set custom field (key=value, repeatable)")

	return cmd
}

func (f *CommandFactory) validateExecuteBeadCreate(cmd *cobra.Command, s *bead.Store, b *bead.Bead) error {
	if os.Getenv(agentpkg.DDXModeEnvKey) != agentpkg.DDXModeBeadExecution {
		return nil
	}
	currentID := strings.TrimSpace(os.Getenv(agentpkg.DDXBeadIDEnvKey))
	if currentID == "" {
		return nil
	}
	reason := ""
	switch {
	case strings.HasPrefix(strings.ToLower(strings.TrimSpace(b.Title)), "sample:"):
		reason = "sample_fixture_title"
	case strings.TrimSpace(b.Parent) == "":
		reason = "missing_current_parent"
	case strings.TrimSpace(b.Parent) != currentID:
		reason = "parent_must_equal_current_bead"
	default:
		parent, err := s.Get(context.Background(), currentID)
		if err != nil {
			return fmt.Errorf("execute-bead child create guard: load parent %s: %w", currentID, err)
		}
		if parent == nil {
			reason = "current_parent_not_found"
		} else if missing := missingExecuteChildLabels(parent.Labels, b.Labels); len(missing) > 0 {
			reason = "missing_parent_labels:" + strings.Join(missing, ",")
		} else if parentSpec := stringExtra(parent.Extra, "spec-id"); parentSpec != "" && stringExtra(b.Extra, "spec-id") != parentSpec {
			reason = "missing_parent_spec_id"
		}
	}
	if reason == "" {
		return nil
	}
	f.appendExecuteBeadCreateRejection(s, currentID, b, reason)
	return fmt.Errorf("execute-bead child create rejected: %s (title=%q parent=%q current=%q)", reason, b.Title, b.Parent, currentID)
}

