			var (
				wg         sync.WaitGroup
				successCnt int32
			)

			for c := 0; c < claimers; c++ {
				c := c
				wg.Add(1)
				go func() {
					defer wg.Done()
					if err := s.Claim(id, fmt.Sprintf("agent-%d", c)); err == nil {
						atomic.AddInt32(&successCnt, 1)
					}
				}()
			}
			wg.Wait()

			// Exactly one claimer must succeed.
