func benchmarkReady(b *testing.B, makeStore benchStoreMaker) {
	b.Helper()
	beads := makeBenchBeads(benchFixtureSize)
	s := prepareBenchStore(b, makeStore, beads)
	b.ReportAllocs()
	b.ResetTimer()
